// Endpoint to validate a user-inserted Gemini API key
app.post("/api/gemini/validate", async (req, res) => {
  const { key } = req.body;
  if (!key || typeof key !== "string" || key.trim() === "") {
    res.status(400).json({ success: false, error: "Chave não informada." });
    return;
  }

  try {
    const tempAi = new GoogleGenAI({
      apiKey: key,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });

    const response = await generateContentWithFallback(tempAi, {
      model: "gemini-3.5-flash",
      contents: "Diga apenas a palavra 'OK' em maiúsculo.",
    });

    if (response.text && response.text.trim().includes("OK")) {
      res.json({ success: true });
    } else {
      res.json({ success: true, warning: "Chave válida, mas formato de resposta inesperado." });
    }
  } catch (err: any) {
    console.error("Erro ao validar chave Gemini:", err);
    res.status(400).json({ success: false, error: err.message || "Chave inválida ou erro na validação." });
  }
});

